    if (topologyStatus.state === "idle") {
      return;
    }
    return scheduleIdleWork(() => {
      setTopologyStatus((current) =>
        current.state === "idle" ? current : { state: "idle", message: "拓扑结果已过期" }
      );
    }, 200, 500);
