            { x: bottomCenter.x - width / 2, y: bottomCenter.y + floatingToolbarGap },
            { x: rightCenter.x + floatingToolbarGap, y: rightCenter.y - height / 2 },
            { x: leftCenter.x - width - floatingToolbarGap, y: leftCenter.y - height / 2 }
